class CallSign
  attr_accessor :sign
  def initialize(sign)
    @sign = sign
  end
  def broadcast
    @sign.upcase
  end
end

class Counter
  attr_reader :count
  def initialize
    @count = 0
  end
  def hit
    @count += 1
    @count
  end
end
